import React, { useEffect, useState, useRef } from 'react';
import { useAuth } from '../context/AuthContext';
import { attendanceAPI } from '../services/api';
import { PageHeader, Card, Table, Btn, Badge, Tabs, Select, Modal, Input, toast } from '../components/ui';
import { LogIn, LogOut, Clock, Edit2 } from 'lucide-react';

export default function Attendance() {
  const { hasRole } = useAuth();
  const [tab, setTab] = useState('clock');
  const [todayStatus, setTodayStatus] = useState(null);
  const [myRecords, setMyRecords] = useState([]);
  const [hrToday, setHrToday] = useState([]);
  const [loading, setLoading] = useState(true);
  const [clocking, setClocking] = useState(false);
  const [editAtt, setEditAtt] = useState(null);
  const [editing, setEditing] = useState(false);
  const [time, setTime] = useState(new Date());
  const timerRef = useRef();

  const now = new Date();
  const [month, setMonth] = useState(now.getMonth() + 1);
  const [year, setYear] = useState(now.getFullYear());

  const isHR = hasRole('hr');

  const tabs = [
    { key: 'clock', label: 'Clock In/Out' },
    { key: 'my', label: 'My Records' },
    ...(isHR ? [{ key: 'hr', label: 'All Employees' }] : []),
  ];

  useEffect(() => {
    timerRef.current = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(timerRef.current);
  }, []);

  const loadToday = async () => {
    try {
      const { data } = await attendanceAPI.today();
      setTodayStatus(data);
    } catch {
      setTodayStatus(null);
    }
  };

  const loadMyRecords = async () => {
    setLoading(true);
    try {
      const { data } = await attendanceAPI.myRecords(month, year);
      setMyRecords(data);
    } catch (e) {
      toast(e.response?.data?.detail || 'Failed to load records', 'error');
    } finally {
      setLoading(false);
    }
  };

  const loadHrToday = async () => {
    setLoading(true);
    try {
      const { data } = await attendanceAPI.hrToday();
      setHrToday(data);
    } catch {
      setHrToday([]);
    } finally {
      setLoading(false);
    }
  };

  const handleAutoClockOut = async () => {
    try {
      const { data } = await attendanceAPI.autoClockOut();
      toast(data.msg || 'Auto clock out executed successfully', 'success');
      loadHrToday();
    } catch {
      toast('Failed to execute auto clock-out', 'error');
    }
  };

  useEffect(() => {
    loadToday();
    setLoading(false);
  }, []);

  useEffect(() => {
    if (tab === 'my') loadMyRecords();
    if (tab === 'hr') loadHrToday();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [tab, month, year]);

  const handleClockIn = async () => {
    setClocking(true);
    try {
      await attendanceAPI.clockIn();
      toast('Clocked in successfully!', 'success');
      loadToday();
    } catch (e) {
      toast(e.response?.data?.detail || 'Failed to clock in', 'error');
    } finally {
      setClocking(false);
    }
  };

  const handleClockOut = async () => {
    setClocking(true);
    try {
      await attendanceAPI.clockOut();
      toast('Clocked out successfully!', 'success');
      loadToday();
    } catch (e) {
      toast(e.response?.data?.detail || 'Failed to clock out', 'error');
    } finally {
      setClocking(false);
    }
  };

  const handleEditSubmit = async (e) => {
    e.preventDefault();
    setEditing(true);
    try {
      await attendanceAPI.hrUpdate(editAtt.id, {
        clock_in: editAtt.clock_in ? new Date(editAtt.clock_in).toISOString() : null,
        clock_out: editAtt.clock_out ? new Date(editAtt.clock_out).toISOString() : null,
        status: editAtt.status,
      });
      toast('Attendance record updated successfully', 'success');
      setEditAtt(null);
      loadHrToday();
    } catch (e) {
      toast(e.response?.data?.detail || 'Failed to update attendance', 'error');
    } finally {
      setEditing(false);
    }
  };

  const formatTime = (dt) => {
    if (!dt) return '—';
    return new Date(dt).toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit' });
  };

  const recordCols = [
    { key: 'date', label: 'Date' },
    { key: 'clock_in', label: 'Clock In', render: (r) => formatTime(r.clock_in) },
    { key: 'clock_out', label: 'Clock Out', render: (r) => formatTime(r.clock_out) },
    { key: 'total_hours', label: 'Hours', render: (r) => r.total_hours ? `${r.total_hours.toFixed(1)}h` : '—' },
    { key: 'is_late', label: 'Late', render: (r) =>
      r.is_late ? <Badge variant="warning">Late</Badge> : <Badge variant="success">On Time</Badge>
    },
    { key: 'status', label: 'Status', render: (r) => (
      <Badge variant={r.status === 'present' ? 'success' : 'neutral'}>{r.status}</Badge>
    )},
  ];

  const hrCols = [
    { key: 'employee_id', label: 'Emp ID' },
    { key: 'date', label: 'Date' },
    { key: 'clock_in', label: 'Clock In', render: (r) => formatTime(r.clock_in) },
    { key: 'clock_out', label: 'Clock Out', render: (r) => formatTime(r.clock_out) },
    { key: 'total_hours', label: 'Hours', render: (r) => {
      if (!r.total_hours) return '—';
      const isBurnout = r.total_hours > 9;
      return (
        <span style={{ 
          color: isBurnout ? 'var(--danger)' : 'inherit', 
          fontWeight: isBurnout ? 700 : 'normal' 
        }}>
          {r.total_hours.toFixed(1)}h {isBurnout && ' ⚠️'}
        </span>
      );
    }},
    { key: 'is_late', label: 'Late', render: (r) =>
      r.is_late ? <Badge variant="warning">Late</Badge> : <Badge variant="success">On Time</Badge>
    },
    { key: 'actions', label: 'Actions', render: (r) => (
      <Btn variant="secondary" size="xs" onClick={() => setEditAtt(r)}>
        <Edit2 size={13} /> Edit
      </Btn>
    )},
  ];

  return (
    <>
      <PageHeader
        title="Attendance"
        subtitle="Track your daily attendance"
      />

      <Tabs tabs={tabs} active={tab} onChange={setTab} />

      {/* Clock In/Out Tab */}
      {tab === 'clock' && (
        <div style={{ display: 'flex', justifyContent: 'center', paddingTop: 20 }}>
          <Card style={{ textAlign: 'center', padding: '40px 60px', maxWidth: 480, width: '100%' }}>
            <div style={{ marginBottom: 8 }}>
              <Clock size={40} color="var(--primary)" strokeWidth={1.5} />
            </div>
            <div
              style={{
                fontSize: 52,
                fontWeight: 700,
                letterSpacing: '-0.03em',
                color: 'var(--text-dark)',
                fontVariantNumeric: 'tabular-nums',
                marginBottom: 6,
              }}
            >
              {time.toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit', second: '2-digit' })}
            </div>
            <div style={{ fontSize: 14, color: 'var(--gray-500)', marginBottom: 28 }}>
              {time.toLocaleDateString('en-IN', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
            </div>

            {/* Today's status */}
            {todayStatus && (
              <div
                style={{
                  background: 'var(--gray-100)',
                  borderRadius: '10px',
                  padding: '14px 20px',
                  marginBottom: 24,
                  textAlign: 'left',
                }}
              >
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 6, fontSize: 13 }}>
                  <span style={{ color: 'var(--gray-500)' }}>Clock In</span>
                  <span style={{ fontWeight: 600 }}>{formatTime(todayStatus.clock_in)}</span>
                </div>
                {todayStatus.clock_out && (
                  <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 6, fontSize: 13 }}>
                    <span style={{ color: 'var(--gray-500)' }}>Clock Out</span>
                    <span style={{ fontWeight: 600 }}>{formatTime(todayStatus.clock_out)}</span>
                  </div>
                )}
                {todayStatus.total_hours != null && (
                  <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 13 }}>
                    <span style={{ color: 'var(--gray-500)' }}>Total Hours</span>
                    <span style={{ fontWeight: 600 }}>{todayStatus.total_hours.toFixed(1)}h</span>
                  </div>
                )}
              </div>
            )}

            <div style={{ display: 'flex', gap: 12, justifyContent: 'center' }}>
              {!todayStatus?.clock_in ? (
                <Btn
                  size="lg"
                  onClick={handleClockIn}
                  loading={clocking}
                  style={{ minWidth: 160, background: 'var(--success)', fontSize: 15 }}
                >
                  <LogIn size={18} /> Clock In
                </Btn>
              ) : !todayStatus?.clock_out ? (
                <Btn
                  size="lg"
                  variant="danger"
                  onClick={handleClockOut}
                  loading={clocking}
                  style={{ minWidth: 160, fontSize: 15 }}
                >
                  <LogOut size={18} /> Clock Out
                </Btn>
              ) : (
                <div
                  style={{
                    background: 'rgba(16, 185, 129, 0.1)',
                    color: 'var(--success)',
                    padding: '12px 24px',
                    borderRadius: '50%',
                    fontWeight: 600,
                    fontSize: 14,
                  }}
                >
                  ✓ Day completed
                </div>
              )}
            </div>
          </Card>
        </div>
      )}

      {/* My Records Tab */}
      {tab === 'my' && (
        <>
          <div style={{ display: 'flex', gap: 12, marginBottom: 16 }}>
            <Select
              value={month}
              onChange={(e) => setMonth(Number(e.target.value))}
              style={{ marginBottom: 0, maxWidth: 160 }}
            >
              {Array.from({ length: 12 }, (_, i) => (
                <option key={i + 1} value={i + 1}>
                  {new Date(2000, i).toLocaleString('en', { month: 'long' })}
                </option>
              ))}
            </Select>
            <Select
              value={year}
              onChange={(e) => setYear(Number(e.target.value))}
              style={{ marginBottom: 0, maxWidth: 120 }}
            >
              {[2024, 2025, 2026, 2027].map((y) => (
                <option key={y} value={y}>{y}</option>
              ))}
            </Select>
          </div>
          <Card style={{ padding: 0, overflow: 'hidden' }}>
            <Table cols={recordCols} rows={myRecords} loading={loading} emptyMsg="No attendance records for this month" />
          </Card>
        </>
      )}

      {/* HR Tab */}
      {tab === 'hr' && (
        <Card style={{ padding: 0, overflow: 'hidden' }}>
          <div style={{ padding: '16px', borderBottom: '1px solid var(--gray-200)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <span style={{ fontWeight: 500 }}>Today's Clock Events</span>
            <Btn size="sm" onClick={handleAutoClockOut}>Force Auto Clock-Out</Btn>
          </div>
          <Table cols={hrCols} rows={hrToday} loading={loading} emptyMsg="No attendance recorded today" />
        </Card>
      )}

      {/* HR Edit Modal */}
      {editAtt && (
        <Modal open={!!editAtt} onClose={() => setEditAtt(null)} title="Edit Attendance (HR Only)">
          <form onSubmit={handleEditSubmit}>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0 16px' }}>
              <Input
                label="Clock In (Datetime)"
                type="datetime-local"
                value={editAtt.clock_in ? editAtt.clock_in.substring(0, 16) : ''}
                onChange={(e) => setEditAtt({ ...editAtt, clock_in: e.target.value })}
                id="edit-att-in"
              />
              <Input
                label="Clock Out (Datetime)"
                type="datetime-local"
                value={editAtt.clock_out ? editAtt.clock_out.substring(0, 16) : ''}
                onChange={(e) => setEditAtt({ ...editAtt, clock_out: e.target.value })}
                id="edit-att-out"
              />
            </div>
            <Select
              label="Status"
              value={editAtt.status || 'present'}
              onChange={(e) => setEditAtt({ ...editAtt, status: e.target.value })}
              id="edit-att-status"
            >
              <option value="present">Present</option>
              <option value="absent">Absent</option>
              <option value="half_day">Half Day</option>
            </Select>
            <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 10, marginTop: 8 }}>
              <Btn variant="secondary" type="button" onClick={() => setEditAtt(null)}>Cancel</Btn>
              <Btn type="submit" loading={editing}>Update Record</Btn>
            </div>
          </form>
        </Modal>
      )}
    </>
  );
}
